// src/App.js
import React, { useState } from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

import Login from "./Login";
import Dashboard from "./Dashboard";
import AddNew from "./AddNew";
import AddTravel from "./AddTravel";
import AddTicket from "./AddTicket";

function App() {
  const [employee, setEmployee] = useState(null);

  return (
    <Router>
      <Routes>
        <Route path="/" element={<Login onLoginSuccess={setEmployee} />} />

        {/* Home / Dashboard */}
        <Route
          path="/dashboard"
          element={<Dashboard employee={employee} />}
        />

        {/* Add New Expense Main Page */}
        <Route
          path="/add"
          element={<AddNew employee={employee} />}
        />

        {/* Travel Form Page */}
        <Route
          path="/add/travel"
          element={<AddTravel employee={employee} />}
        />

        {/* Ticket Form Page */}
        <Route
          path="/add/ticket"
          element={<AddTicket employee={employee} />}
        />
      </Routes>
    </Router>
  );
}

export default App;
